# Quest System
class Quest:
    def __init__(self, name):
        self.name = name
        self.steps = []
        self.done = False

    def add_step(self, step):
        self.steps.append(step)

    def complete(self):
        self.done = True
        return f"{self.name} done!"

    def progress(self):
        total = len(self.steps)
        finished = sum(1 for s in self.steps
                       if s.get("done"))
        return f"{finished}/{total}"

    def reset(self):
        self.done = False
        for s in self.steps:
            s["done"] = False

def load_quests(path):
    quests = []
    print(f"Loading from {path}")
    return quests
